import{_ as e,o as d,c as s,ag as o}from"./chunks/framework.BBBcTwIo.js";const g=JSON.parse('{"title":"Scripts & Tooling","description":"","frontmatter":{},"headers":[],"relativePath":"scripts.md","filePath":"scripts.md"}'),a={name:"scripts.md"};function r(c,t,i,n,l,p){return d(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="scripts-tooling" tabindex="-1">Scripts &amp; Tooling <a class="header-anchor" href="#scripts-tooling" aria-label="Permalink to &quot;Scripts &amp; Tooling&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <code>scripts/</code> directory contains ~60 Node.js utility scripts for asset conversion, database management, SEO generation, and batch operations. Most are run with <code>node scripts/&lt;name&gt;.js</code> or <code>npx tsx scripts/&lt;name&gt;.ts</code>.</p><hr><h2 id="data-analysis-processing" tabindex="-1">Data Analysis &amp; Processing <a class="header-anchor" href="#data-analysis-processing" aria-label="Permalink to &quot;Data Analysis &amp; Processing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Script</th><th>Purpose</th><th>Usage</th></tr></thead><tbody><tr><td><code>analyze-saved-designs.js</code></td><td>Analyze saved designs; regenerate <code>saved-designs-data.ts</code></td><td><code>node scripts/analyze-saved-designs.js</code></td></tr><tr><td><code>categorize-saved-designs.js</code></td><td>Categorize designs from ML exports for programmatic SEO</td><td><code>node scripts/categorize-saved-designs.js</code></td></tr><tr><td><code>categorize-saved-designs-enhanced.js</code></td><td>Enhanced categorization using filename patterns</td><td><code>node scripts/categorize-saved-designs-enhanced.js</code></td></tr><tr><td><code>dedup-designs.ts</code></td><td>Smart dedup with word overlap &amp; feature growth detection</td><td><code>npx tsx scripts/dedup-designs.ts [--dry-run]</code></td></tr><tr><td><code>audit-pets-category.js</code></td><td>Audit Pets category using text analysis &amp; ML</td><td><code>node scripts/audit-pets-category.js [--with-images] [--apply]</code></td></tr><tr><td><code>extract-inscription-phrases.js</code></td><td>Extract unique inscription phrases from designs</td><td><code>node scripts/extract-inscription-phrases.js</code></td></tr><tr><td><code>extract-short-phrases.js</code></td><td>Extract reusable short phrases (≤6 words, no names/dates)</td><td><code>node scripts/extract-short-phrases.js</code></td></tr><tr><td><code>generate-unique-slugs.js</code></td><td>Generate SEO-optimized unique slugs for all designs</td><td><code>node scripts/generate-unique-slugs.js</code></td></tr><tr><td><code>import-reviewed-phrases.js</code></td><td>Import reviewed phrases and update slug generation</td><td><code>node scripts/import-reviewed-phrases.js</code></td></tr><tr><td><code>generate-saved-designs-ts.js</code></td><td>Generate <code>saved-designs-data.ts</code> from analyzed JSON</td><td><code>node scripts/generate-saved-designs-ts.js</code></td></tr><tr><td><code>generate-screenshot-metadata.js</code></td><td>Generate metadata JSON for cropped screenshots</td><td><code>node scripts/generate-screenshot-metadata.js</code></td></tr></tbody></table><h2 id="database-management" tabindex="-1">Database Management <a class="header-anchor" href="#database-management" aria-label="Permalink to &quot;Database Management&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Script</th><th>Purpose</th><th>Usage</th></tr></thead><tbody><tr><td><code>setup-database.js</code></td><td>Automated DB setup (schema + seed + verify)</td><td><code>node scripts/setup-database.js</code></td></tr><tr><td><code>export-database.js</code></td><td>Export local PostgreSQL database</td><td><code>node scripts/export-database.js</code></td></tr><tr><td><code>sync-to-neon.js</code></td><td>Backup &amp; sync local PostgreSQL to Neon</td><td><code>node scripts/sync-to-neon.js</code></td></tr><tr><td><code>import-to-neon.js</code></td><td>Import SQL dump to Neon</td><td><code>node scripts/import-to-neon.js</code></td></tr><tr><td><code>verify-database.js</code></td><td>Verify all tables and seed data</td><td><code>node scripts/verify-database.js</code></td></tr><tr><td><code>test-db.js</code> / <code>test-db.ts</code></td><td>Database connection &amp; query tests</td><td><code>node scripts/test-db.js</code></td></tr></tbody></table><h2 id="seeding-migration" tabindex="-1">Seeding &amp; Migration <a class="header-anchor" href="#seeding-migration" aria-label="Permalink to &quot;Seeding &amp; Migration&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Script</th><th>Purpose</th><th>Usage</th></tr></thead><tbody><tr><td><code>seed-test-user.mjs</code></td><td>Seed test user data</td><td><code>node scripts/seed-test-user.mjs</code></td></tr><tr><td><code>seed-shapes.ts</code></td><td>Seed shapes table</td><td><code>npx tsx scripts/seed-shapes.ts</code></td></tr><tr><td><code>seed-materials.ts</code></td><td>Seed materials table</td><td><code>npx tsx scripts/seed-materials.ts</code></td></tr><tr><td><code>seed-additions.ts</code></td><td>Seed additions table</td><td><code>npx tsx scripts/seed-additions.ts</code></td></tr><tr><td><code>migrate-individual-motifs.js</code></td><td>Migrate individual motif data</td><td><code>node scripts/migrate-individual-motifs.js</code></td></tr><tr><td><code>migrate-motif-categories.js</code></td><td>Populate 49 motif categories from data</td><td><code>npx tsx scripts/migrate-motif-categories.js</code></td></tr></tbody></table><h2 id="asset-conversion" tabindex="-1">Asset Conversion <a class="header-anchor" href="#asset-conversion" aria-label="Permalink to &quot;Asset Conversion&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Script</th><th>Purpose</th><th>Usage</th></tr></thead><tbody><tr><td><code>convert-jpg-to-webp.js</code></td><td>Batch convert JPG → WebP (85% quality)</td><td><code>node scripts/convert-jpg-to-webp.js</code></td></tr><tr><td><code>convert-textures-to-webp.js</code></td><td>Convert all JPEG textures → WebP</td><td><code>node scripts/convert-textures-to-webp.js</code></td></tr><tr><td><code>convert-to-gltf.js</code></td><td>Convert 3D models → glTF format</td><td><code>node scripts/convert-to-gltf.js</code></td></tr><tr><td><code>convert-legacy-design.js</code></td><td>Convert legacy saved-design JSON → canonical v2026</td><td><code>node scripts/convert-legacy-design.js &lt;id&gt; [--mlDir] [--version] [--spec]</code></td></tr><tr><td><code>convert-p3d-design.js</code></td><td>Convert legacy P3D files (monuments) → canonical JSON</td><td><code>node scripts/convert-p3d-design.js [designId]</code></td></tr><tr><td><code>batch-convert-additions.js</code></td><td>Batch convert FBX/3DS → glTF</td><td><code>node scripts/batch-convert-additions.js</code></td></tr><tr><td><code>batch-convert-saved-designs.js</code></td><td>Batch convert saved designs format</td><td><code>node scripts/batch-convert-saved-designs.js</code></td></tr><tr><td><code>png-to-glb.js</code></td><td>PNG → GLB with 3D relief (brightness-based depth)</td><td><code>node scripts/png-to-glb.js</code></td></tr></tbody></table><h2 id="screenshot-thumbnail-generation" tabindex="-1">Screenshot &amp; Thumbnail Generation <a class="header-anchor" href="#screenshot-thumbnail-generation" aria-label="Permalink to &quot;Screenshot &amp; Thumbnail Generation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Script</th><th>Purpose</th><th>Usage</th></tr></thead><tbody><tr><td><code>batch-screenshot.js</code></td><td>Batch screenshot generator with anonymization</td><td><code>node scripts/batch-screenshot.js [--skip-existing] [--category=pets] [--limit=10]</code></td></tr><tr><td><code>crop-screenshots.js</code></td><td>Batch crop screenshots (remove white borders)</td><td><code>node scripts/crop-screenshots.js</code></td></tr><tr><td><code>generate-addition-thumbnails.js</code></td><td>Generate thumbnails for additions</td><td><code>node scripts/generate-addition-thumbnails.js</code></td></tr></tbody></table><blockquote><p><strong>Note</strong>: <code>batch-screenshot.js</code> requires the dev server running on port 3000. Use <code>npx next dev --turbopack</code> first.</p></blockquote><h2 id="seo-content-generation" tabindex="-1">SEO &amp; Content Generation <a class="header-anchor" href="#seo-content-generation" aria-label="Permalink to &quot;SEO &amp; Content Generation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Script</th><th>Purpose</th><th>Usage</th></tr></thead><tbody><tr><td><code>generate-additions-data.js</code></td><td>Generate additions data from folder structure</td><td><code>node scripts/generate-additions-data.js</code></td></tr><tr><td><code>generate-seo-from-ml-consolidated.js</code></td><td>Generate SEO data from consolidated ML exports</td><td><code>node scripts/generate-seo-from-ml-consolidated.js</code></td></tr><tr><td><code>generate-seo-json-split.js</code></td><td>Generate split SEO JSON files</td><td><code>node scripts/generate-seo-json-split.js</code></td></tr><tr><td><code>generate-seo-templates-from-ml.js</code></td><td>Generate SEO templates from ML data</td><td><code>node scripts/generate-seo-templates-from-ml.js</code></td></tr><tr><td><code>generate-unified-seo-templates.js</code></td><td>Generate unified SEO templates</td><td><code>node scripts/generate-unified-seo-templates.js</code></td></tr><tr><td><code>generate-sitemap.ts</code></td><td>Generate XML sitemap</td><td><code>npx tsx scripts/generate-sitemap.ts</code></td></tr></tbody></table><h2 id="cache-utilities" tabindex="-1">Cache &amp; Utilities <a class="header-anchor" href="#cache-utilities" aria-label="Permalink to &quot;Cache &amp; Utilities&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Script</th><th>Purpose</th><th>Usage</th></tr></thead><tbody><tr><td><code>clear-all-caches.js</code></td><td>Clear Next.js build cache and SVG cache</td><td><code>node scripts/clear-all-caches.js</code></td></tr><tr><td><code>clear-svg-cache.js</code></td><td>Clear expired SVG cache</td><td><code>node scripts/clear-svg-cache.js</code></td></tr><tr><td><code>svg-cache-stats.js</code></td><td>Show SVG cache statistics</td><td><code>node scripts/svg-cache-stats.js</code></td></tr><tr><td><code>validate-design-layouts.js</code></td><td>Validate inscription/motif layouts fit on products</td><td><code>node scripts/validate-design-layouts.js</code></td></tr><tr><td><code>validate-design-layouts-v2.js</code></td><td>V2 layout validation</td><td><code>node scripts/validate-design-layouts-v2.js</code></td></tr><tr><td><code>report-rollout-summary.js</code></td><td>Generate rollout summary report</td><td><code>node scripts/report-rollout-summary.js</code></td></tr><tr><td><code>apply-layout-fixes.js</code></td><td>Apply layout fixes to designs</td><td><code>node scripts/apply-layout-fixes.js</code></td></tr></tbody></table><h2 id="python-utilities" tabindex="-1">Python Utilities <a class="header-anchor" href="#python-utilities" aria-label="Permalink to &quot;Python Utilities&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Script</th><th>Purpose</th><th>Usage</th></tr></thead><tbody><tr><td><code>fix-pet-false-positives.py</code></td><td>Fix miscategorized pet designs</td><td><code>python scripts/fix-pet-false-positives.py</code></td></tr><tr><td><code>scan-pet-designs.py</code></td><td>Scan and reclassify pet designs</td><td><code>python scripts/scan-pet-designs.py</code></td></tr></tbody></table><hr><h2 id="static-assets-public" tabindex="-1">Static Assets (<code>public/</code>) <a class="header-anchor" href="#static-assets-public" aria-label="Permalink to &quot;Static Assets (`public/`)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Directory</th><th>Content</th><th>Approximate Size</th></tr></thead><tbody><tr><td><code>public/textures/</code></td><td>Granite/material WebP textures</td><td>~17 MB</td></tr><tr><td><code>public/shapes/</code></td><td>SVG headstone outlines</td><td>Small</td></tr><tr><td><code>public/additions/</code></td><td>GLB 3D models + thumbnails</td><td>Large</td></tr><tr><td><code>public/motifs/</code></td><td>Decorative SVGs &amp; PNGs</td><td>Medium</td></tr><tr><td><code>public/designs/</code></td><td>Canonical design JSONs (v2026, v2026-p3d)</td><td>Medium</td></tr><tr><td><code>public/hdri/</code></td><td>HDRI environment maps</td><td>~27 MB</td></tr><tr><td><code>public/fonts/</code></td><td>Font files</td><td>Small</td></tr><tr><td><code>public/emblems/</code></td><td>Emblem/insignia graphics</td><td>~33 MB</td></tr><tr><td><code>public/png/</code></td><td>PNG image assets</td><td>~343 MB</td></tr><tr><td><code>public/ml/</code></td><td>Legacy ML exports &amp; saved designs</td><td>Large</td></tr><tr><td><code>public/screenshots/</code></td><td>Screenshot captures (v2026-3d)</td><td>~186 MB</td></tr><tr><td><code>public/xml/</code></td><td>Product catalog &amp; pricing XMLs</td><td>Small</td></tr><tr><td><code>public/workers/</code></td><td>Web Worker scripts</td><td>Small</td></tr><tr><td><code>public/upload/</code></td><td>User-uploaded images</td><td>Variable</td></tr></tbody></table><p><strong>Total public assets</strong>: ~1.2 GB</p><hr><h2 id="data-files-data" tabindex="-1">Data Files (<code>data/</code>) <a class="header-anchor" href="#data-files-data" aria-label="Permalink to &quot;Data Files (`data/`)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>additions-parsed.json</code></td><td>Parsed additions configuration</td></tr><tr><td><code>favorite-designs.json</code></td><td>User favorite design IDs</td></tr><tr><td><code>hidden-designs.json</code></td><td>Hidden/archived design IDs (793 entries from dedup)</td></tr></tbody></table><hr><h2 id="global-styles-styles-globals-css" tabindex="-1">Global Styles (<code>styles/globals.css</code>) <a class="header-anchor" href="#global-styles-styles-globals-css" aria-label="Permalink to &quot;Global Styles (`styles/globals.css`)&quot;">​</a></h2><p>Tailwind CSS 4 with custom rules:</p><ul><li>Caret color suppressed globally (except inputs/textarea/contenteditable)</li><li>Cursor defaults to <code>default</code> except on buttons, links, text inputs</li><li>Button hover effects with shadow/scale transforms</li><li>Link underline animations</li><li>Source directories: <code>app/</code>, <code>components/</code>, <code>contexts/</code>, <code>lib/</code>, <code>ui/</code></li></ul><hr><h2 id="react-context-contexts" tabindex="-1">React Context (<code>contexts/</code>) <a class="header-anchor" href="#react-context-contexts" aria-label="Permalink to &quot;React Context (`contexts/`)&quot;">​</a></h2><p>Single context: <strong>NavigationContext</strong> (<code>NavigationContext.tsx</code>)</p><table tabindex="0"><thead><tr><th>Export</th><th>Purpose</th></tr></thead><tbody><tr><td><code>isMobileNavOpen</code></td><td>Mobile nav open state</td></tr><tr><td><code>setIsMobileNavOpen()</code></td><td>Set mobile nav state</td></tr><tr><td><code>toggleMobileNav()</code></td><td>Toggle mobile nav</td></tr><tr><td><code>useNavigation()</code></td><td>Hook for accessing context</td></tr></tbody></table>',36)])])}const b=e(a,[["render",r]]);export{g as __pageData,b as default};
